use crate::decoders::{Crack, CrackResult, Decoder, check_string_success};use crate::checkers::CheckerTypes;use std::marker::PhantomData;pub struct Z85Decoder;impl Crack for Decoder<Z85Decoder> {    fn crack(&self, text: &str, checker: &CheckerTypes) -> CrackResult {        let mut result = CrackResult::new(self.get_name(), self.get_description(), self.get_link());        result.encrypted_text = text.to_string();        let mut cleaned: String = text.chars().filter(|c| !c.is_whitespace()).collect();        if cleaned.len() % 5 != 0 {            let pad_len = 5 - (cleaned.len() % 5);            cleaned.push_str(&"\0".repeat(pad_len));        }        let z85_alphabet = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ.-:+=^!/*?&<>()[]{}@%$#";        let valid: std::collections::HashSet<char> = z85_alphabet.chars().collect();        if !cleaned.chars().all(|c| valid.contains(&c)) {            return result;        }        let chars: Vec<char> = cleaned.chars().collect();        let mut bytes = Vec::with_capacity(chars.len() * 4 / 5);        for chunk in chars.chunks(5) {            if chunk.len() < 5 { break; }            let mut value: u32 = 0;            for &c in chunk {                if let Some(pos) = z85_alphabet.find(c) {                    value = value * 85 + pos as u32;                } else {                    return result;                }            }            bytes.extend_from_slice(&value.to_be_bytes());        }        if let Ok(decoded_str) = String::from_utf8(bytes) {            let decoded = decoded_str.trim_end_matches('\0').to_string();            if check_string_success(&decoded, text) {                let check_result = checker.check_text(&decoded);                if check_result.is_identified {                    result.success = true;                    result.unencrypted_text = Some(vec![decoded]);                    result.checker_name = check_result.checker_name;                }            }        }        result    }    fn get_name(&self) -> &'static str { "Z85" }    fn get_popularity(&self) -> f32 { 0.3 }    fn get_tags(&self) -> &'static [&'static str] { &["z85", "decoder", "base", "encoding"] }    fn get_description(&self) -> &'static str { "Z85 (ZeroMQ Base-85) is a binary-to-text encoding that encodes binary data in base-85." }    fn get_link(&self) -> &'static str { "https://rfc.zeromq.org/spec/32/" }}impl Decoder<Z85Decoder> {    pub fn new() -> Self {        Decoder {            name: "Z85",            description: "Z85 (ZeroMQ Base-85) is a binary-to-text encoding.",            link: "https://rfc.zeromq.org/spec/32/",            tags: vec!["z85", "decoder", "base", "encoding"],            popularity: 0.3,            phantom: PhantomData,        }    }}



